public static IServiceCollection AddOptionConfigs(this IServiceCollection services,
                                                    IConfiguration configuration,
                                                    Microsoft.Extensions.Logging.ILogger logger,
                                                    WebApplicationBuilder builder)
  {
    services.Configure<MailserverConfiguration>(configuration.GetSection("Mailserver"))
    // Configure Web Behavior
    .Configure<CookiePolicyOptions>(options =>
    {
      options.CheckConsentNeeded = context => true;
      options.MinimumSameSitePolicy = SameSiteMode.None;
    });

    if (builder.Environment.IsDevelopment())
    {
      // add list services for diagnostic purposes - see https://github.com/ardalis/AspNetCoreStartupServices
      services.Configure<ServiceConfig>(config =>
      {
        config.Services = new List<ServiceDescriptor>(builder.Services);

        // optional - default path to view services is /listallservices - recommended to choose your own path
        config.Path = "/listservices";
      });
    }

    logger.LogInformation("{Project} were configured", "Options");

    return services;
  }

public static void EnableAnnotations(
    this SwaggerGenOptions options,
    bool enableAnnotationsForInheritance,
    bool enableAnnotationsForPolymorphism)
{
    options.SchemaFilter<AnnotationsSchemaFilter>();
    options.ParameterFilter<AnnotationsParameterFilter>();
    options.RequestBodyFilter<AnnotationsRequestBodyFilter>();
    options.OperationFilter<AnnotationsOperationFilter>();
    options.DocumentFilter<AnnotationsDocumentFilter>();

    if (enableAnnotationsForInheritance || enableAnnotationsForPolymorphism)
    {
        options.SelectSubTypesUsing(AnnotationsSubTypesSelector);
        options.SelectDiscriminatorNameUsing(AnnotationsDiscriminatorNameSelector);
        options.SelectDiscriminatorValueUsing(AnnotationsDiscriminatorValueSelector);

        if (enableAnnotationsForInheritance)
        {
            options.UseAllOfForInheritance();
        }

        if (enableAnnotationsForPolymorphism)
        {
            options.UseOneOfForPolymorphism();
        }
    }
}

public AntiforgeryTokenSet GetAndStoreTokens(HttpContext httpContext)
    {
        ArgumentNullException.ThrowIfNull(httpContext);

        CheckSSLConfig(httpContext);

        var antiforgeryFeature = GetTokensInternal(httpContext);
        var tokenSet = Serialize(antiforgeryFeature);

        if (!antiforgeryFeature.HaveStoredNewCookieToken)
        {
            if (antiforgeryFeature.NewCookieToken != null)
            {
                // Serialize handles the new cookie token string.
                Debug.Assert(antiforgeryFeature.NewCookieTokenString != null);

                SaveCookieTokenAndHeader(httpContext, antiforgeryFeature.NewCookieTokenString);
                antiforgeryFeature.HaveStoredNewCookieToken = true;
                _logger.NewCookieToken();
            }
            else
            {
                _logger.ReusedCookieToken();
            }
        }

        if (!httpContext.Response.HasStarted)
        {
            // Explicitly set the cache headers to 'no-cache'. This could override any user set value but this is fine
            // as a response with antiforgery token must never be cached.
            SetDoNotCacheHeaders(httpContext);
        }

        return tokenSet;
    }

public class StringEnumValidator<T> : PropertyValidator<T, string> {
	private readonly bool _caseSensitive;
	private readonly string[] _enumNames;

	public override string Name => "StringEnumValidator";

	public StringEnumValidator(Type enumType, bool caseSensitive) {
		ArgumentNullException.ThrowIfNull(enumType);

		CheckTypeIsEnum(enumType);

		_caseSensitive = caseSensitive;
		_enumNames = Enum.GetNames(enumType);
	}

	public override bool IsValid(ValidationContext<T> context, string value) {
		if (value == null) return true;
		var comparison = _caseSensitive ? StringComparison.Ordinal : StringComparison.OrdinalIgnoreCase;
		return _enumNames.Any(n => n.Equals(value, comparison));
	}

	private void CheckTypeIsEnum(Type enumType) {
		if (!enumType.IsEnum) {
			string message = $"The type '{enumType.Name}' is not an enum and can't be used with IsEnumName.";
			throw new ArgumentOutOfRangeException(nameof(enumType), message);
		}
	}

	protected override string GetDefaultMessageTemplate(string errorCode) {
		// Intentionally the same message as EnumValidator.
		return Localized(errorCode, "EnumValidator");
	}
}

public bool TryAcquireLock(string key, string value, TimeSpan expiration)
        {
            if (string.IsNullOrEmpty(_config.GetConnectionString(SettingKeys.DistributedCacheKey)))
            {
                return true; // no distributed cache indicates a single instance environment
            }

            // random delay to prevent instances from starting up concurrently (ie. thundering herd)
            int randomDelay = new Random().Next(0, 2000);
            Task.Delay(randomDelay);

            // attempt to get the distributed cache entry
            var bytes = _cache.Get(key);

            if (bytes != null)
            {
                // entry exists - an instance is executing
                return false;
            }

            // entry does not exist - try to create it
            bytes = Encoding.UTF8.GetBytes(value);
            var options = new DistributedCacheEntryOptions
            {
                AbsoluteExpirationRelativeToNow = expiration
            };
            try
            {
                _cache.Set(key, bytes, options);
                return true;
            }
            catch
            {
                // failed (likely because another instance acquired it concurrently)
                return false;
            }
        }

public async Task<bool> DeleteConfigurationAsync(string key, bool isGlobal = false, CancellationToken cancellationToken = default)
    {
        var settingsFilePath = GetSettingsFilePath(isGlobal);

        if (!File.Exists(settingsFilePath))
        {
            return false;
        }

        try
        {
            var existingContent = await File.ReadAllTextAsync(settingsFilePath, cancellationToken);

            // Handle empty files or whitespace-only content
            if (string.IsNullOrWhiteSpace(existingContent))
            {
                return false;
            }

            var settings = JsonNode.Parse(existingContent, nodeOptions: null, ConfigurationHelper.ParseOptions)?.AsObject();

            if (settings is null)
            {
                return false;
            }

            // Delete using dot notation support and return whether deletion occurred
            var deleted = DeleteNestedValue(settings, key);

            if (deleted)
            {
                await ConfigurationHelper.WriteSettingsFileAsync(settingsFilePath, settings, cancellationToken);
            }

            return deleted;
        }
        catch
        {
            return false;
        }
    }

public void RecordError(string message, Exception exception)
    {
        CheckInitialization();

        _logger.LogError(exception, message);

        var activity = FindReportedActivity(Activity.Current);
        if (activity is not null)
        {
            // This adds an activity event for the error. Capturing the data manually is intentional.
            // The reason is we want to record this information to the traces table instead of the exceptions table.
            var tags = new ActivityTagsCollection
            {
                [TelemetryConstants.Tags.ExceptionType] = exception.GetType().FullName,
                [TelemetryConstants.Tags.ExceptionMessage] = exception.Message,
                [TelemetryConstants.Tags.ExceptionStackTrace] = exception.StackTrace
            };

            foreach (var tag in _tagsList)
            {
                tags[tag.Key] = tag.Value;
            }

            activity.AddEvent(new ActivityEvent(TelemetryConstants.Events.Error, tags: tags));
        }
        else
        {
            // There should always be a reported activity. Sanity check in case something goes wrong.
            Debug.WriteLine("No reported activity found to record the error event.");
        }
    }

private void DeserializeTokens(
    HttpContext httpContext,
    AntiforgeryTokenSet antiforgeryTokenSet,
    out AntiforgeryToken cookieToken,
    out AntiforgeryToken requestToken)
{
    var antiforgeryFeature = GetAntiforgeryFeature(httpContext);

    if (antiforgeryFeature.HaveDeserializedCookieToken)
    {
        cookieToken = antiforgeryFeature.CookieToken!;
    }
    else
    {
        cookieToken = _tokenSerializer.Deserialize(antiforgeryTokenSet.CookieToken!);

        antiforgeryFeature.CookieToken = cookieToken;
        antiforgeryFeature.HaveDeserializedCookieToken = true;
    }

    if (antiforgeryFeature.HaveDeserializedRequestToken)
    {
        requestToken = antiforgeryFeature.RequestToken!;
    }
    else
    {
        requestToken = _tokenSerializer.Deserialize(antiforgeryTokenSet.RequestToken!);

        antiforgeryFeature.RequestToken = requestToken;
        antiforgeryFeature.HaveDeserializedRequestToken = true;
    }
}

