public static void AddActivityContextToEnvironment(Activity? activity, IDictionary<string, string> environment)
    {
        if (activity is null)
        {
            return;
        }

        var sessionId = GetProfilingSessionId(activity);
        if (string.IsNullOrWhiteSpace(sessionId))
        {
            return;
        }

        environment[EnvironmentVariables.Enabled] = "true";
        environment[KnownConfigNames.Legacy.StartupProfilingEnabled] = "true";
        environment[EnvironmentVariables.SessionId] = sessionId;
        environment[KnownConfigNames.Legacy.StartupOperationId] = sessionId;

        if (!string.IsNullOrWhiteSpace(activity.Id))
        {
            environment[EnvironmentVariables.TraceParent] = activity.Id;
            environment[KnownConfigNames.Legacy.StartupTraceParent] = activity.Id;
        }

        if (!string.IsNullOrWhiteSpace(activity.TraceStateString))
        {
            environment[EnvironmentVariables.TraceState] = activity.TraceStateString;
            environment[KnownConfigNames.Legacy.StartupTraceState] = activity.TraceStateString;
        }
    }

private static TimeSpan GetBreakDuration(int? milliseconds)
    {
        var ms = milliseconds.HasValue && milliseconds.Value > LowBreakDuration
            ? milliseconds.Value : DefaultBreakDuration;
        return TimeSpan.FromMilliseconds(ms);
    }

    private static int GetMinimumThroughput(int? minimumThroughput)
    {
        var min = minimumThroughput.HasValue && minimumThroughput.Value >= LowMinimumThroughput
            ? minimumThroughput.Value : DefaultMinimumThroughput;
        return min;
    }

    private static double GetFailureRatio(double failureRatio)
        => failureRatio > LowFailureRatio && failureRatio <= 1.0 ? failureRatio : DefaultFailureRatio;

    private static TimeSpan GetSamplingDuration(int? milliseconds)
    {
        var ms = milliseconds.HasValue && milliseconds.Value > LowSamplingDuration
            ? milliseconds.Value : DefaultSamplingDuration;
        return TimeSpan.FromMilliseconds(ms);
    }

    private static int? GetTimeout(int? milliseconds)
    {
        if (!milliseconds.HasValue || milliseconds.Value <= 0)
            return null; // not configured or explicitly disabled
        return milliseconds.Value > LowTimeout && milliseconds.Value < HighTimeout
            ? milliseconds.Value : DefaultTimeout;
    }

internal bool IsDisabledDate(DateTime input)
        {
            var disabledCurrentDate = DisabledDate is not null && DisabledDate(input);
            if (!disabledCurrentDate)
            {
                return false;
            }

            var isInitialPickerType = Picker == _pickerStatus[0].InitPicker;

            if (isInitialPickerType)
            {
                return disabledCurrentDate;
            }

            var currentPeriodStartDate = DateHelper.FormatDateByPicker(input, Picker);
            var currentPeriodEndDate = DateHelper.GetNextStartDateOfPeriod(input, Picker).AddDays(-1);

            // This loop can be optimized so that if it is already available in the lower period, the current period is also available.
            for (var curr = currentPeriodStartDate; curr < currentPeriodEndDate; curr = curr.AddDays(1))
            {
                if (!DisabledDate(curr))
                {
                    return false;
                }
            }

            return disabledCurrentDate;
        }

private EmbeddedAspireSkillsBundleMetadata? LoadMetadata()
    {
        using var stream = typeof(EmbeddedAspireSkillsBundleProvider).Assembly.GetManifestResourceStream(MetadataResourceName);
        if (stream is null)
        {
            _logger.LogDebug("Embedded Aspire skills metadata resource {ResourceName} was not found.", MetadataResourceName);
            return null;
        }

        try
        {
            var metadata = JsonSerializer.Deserialize(
                stream,
                AspireSkillsJsonSerializerContext.Default.EmbeddedAspireSkillsBundleMetadata);

            if (metadata is null)
            {
                _logger.LogDebug("Embedded Aspire skills metadata resource {ResourceName} was empty.", MetadataResourceName);
            }

            return metadata;
        }
        catch (JsonException ex)
        {
            _logger.LogWarning(ex, "Embedded Aspire skills metadata resource {ResourceName} could not be parsed.", MetadataResourceName);
            return null;
        }
    }

public static async Task<IReadOnlyList<InstallationInfo>> DiscoverAllSafelyAsync(
    IInstallationDiscovery discovery,
    WingetFirstRunProbe wingetFirstRunProbe,
    ILogger logger,
    CancellationToken cancellationToken)
{
    try
    {
        RunWingetFirstRunProbe(wingetFirstRunProbe);
    }
    catch (Exception ex) when (ex is not OperationCanceledException)
    {
        logger.LogWarning(ex, "Could not run the winget first-run install sidecar probe before doctor installation discovery.");
    }

    try
    {
        logger.LogDebug("Discovering Aspire CLI installations for doctor output.");
        var installations = await discovery.DiscoverAllAsync(cancellationToken).ConfigureAwait(false);
        logger.LogDebug("Discovered {InstallationCount} Aspire CLI installation(s) for doctor output.", installations.Count);
        return installations;
    }
    catch (OperationCanceledException)
    {
        throw;
    }
    catch (Exception ex)
    {
        logger.LogWarning(ex, "Could not discover Aspire CLI installations for doctor output.");
        return CreateFailedDiscoveryRow();
    }
}

