public async Task<bool> InstallGlobalAsync(string tarballPath, CancellationToken cancellationToken)
    {
        var npmPath = FindNpmPath();
        if (npmPath is null)
        {
            return false;
        }

        logger.LogDebug("Installing npm package globally from {TarballPath}", tarballPath);

        // Use an isolated temp subdirectory so npm doesn't pick up .npmrc or
        // other config files from the shared temp root or the user's CWD.
        var tempDir = CreateIsolatedTempDirectory();

        try
        {
            var output = await RunNpmCommandInDirectoryAsync(
                npmPath,
                ["install", "-g", tarballPath],
                tempDir,
                cancellationToken);

            if (output is null)
            {
                logger.LogDebug("Failed to install npm package globally from {TarballPath}", tarballPath);
                return false;
            }

            logger.LogDebug("Successfully installed npm package globally from {TarballPath}", tarballPath);
            return true;
        }
        finally
        {
            CleanupTempDirectory(tempDir);
        }
    }

internal static void ConfigureSingleFileRunEnvironment(
    FileInfo appHostFile,
    Dictionary<string, string> env,
    IReadOnlyDictionary<string, string?>? inheritedEnvironmentVariables = null,
    string[]? args = null)
{
    var runJsonFilePath = appHostFile.FullName[..^2] + "run.json";
    if (File.Exists(runJsonFilePath))
    {
        // dotnet run reads the launch profile from apphost.run.json natively, so the CLI
        // does not need to inject any environment variables itself.
        return;
    }

    // No apphost.run.json — fall back to aspire.config.json profiles (if any), then to
    // hardcoded defaults. ApplyEffectiveEnvironment is always called last so that explicit
    // --environment arguments still win.
    if (!TryApplyAspireConfigProfile(appHostFile, env, filterEnvironmentNames: false))
    {
        ApplyDefaultSingleFileEndpoints(env);
    }

    AppHostEnvironmentDefaults.ApplyEffectiveEnvironment(
        env,
        AppHostEnvironmentDefaults.DevelopmentEnvironmentName,
        inheritedEnvironmentVariables,
        args);
}

public JsonDocument ParseProject(FileInfo projectFile)
    {
        try
        {
            _logger.LogDebug("Parsing project file '{ProjectFile}' using fallback parser", projectFile.FullName);

            // Detect file type and route to appropriate parser
            if (string.Equals(projectFile.Extension, ".csproj", StringComparison.OrdinalIgnoreCase))
            {
                return ParseCsprojProjectFile(projectFile);
            }
            else if (string.Equals(projectFile.Extension, ".cs", StringComparison.OrdinalIgnoreCase))
            {
                return ParseCsAppHostFile(projectFile);
            }
            else
            {
                throw new ProjectUpdaterException($"Unsupported project file type: {projectFile.Extension}. Expected .csproj or .cs file.");
            }
        }
        catch (ProjectUpdaterException)
        {
            // Re-throw our custom exceptions
            throw;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to parse project file '{ProjectFile}' using fallback parser", projectFile.FullName);
            throw new ProjectUpdaterException($"Failed to parse project file '{projectFile.FullName}' using fallback parser: {ex.Message}", ex);
        }
    }

internal static Dictionary<string, string> CreateGuestEnvironmentVariables(
    IDictionary<string, string> contextEnvironmentVariables,
    IDictionary<string, string>? launchProfileEnvironmentVariables,
    IDictionary<string, string>? additionalEnvironmentVariables = null,
    string? defaultEnvironment = null,
    bool includeLaunchProfileEnvironmentVariables = true,
    IReadOnlyDictionary<string, string?>? inheritedEnvironmentVariables = null,
    string[]? args = null)
{
    var environmentVariables = new Dictionary<string, string>(contextEnvironmentVariables);

    MergeLaunchProfileEnvironmentVariables(
        launchProfileEnvironmentVariables,
        environmentVariables,
        includeLaunchProfileEnvironmentVariables);

    if (additionalEnvironmentVariables is not null)
    {
        foreach (var (key, value) in additionalEnvironmentVariables)
        {
            environmentVariables[key] = value;
        }
    }

    AppHostEnvironmentDefaults.ApplyEffectiveEnvironment(environmentVariables, defaultEnvironment, inheritedEnvironmentVariables, args);

    return environmentVariables;
}

public async Task<SecretsStoreResult?> ResolveAsync(
    FileInfo? projectFile,
    bool autoInit,
    CancellationToken cancellationToken)
{
    var searchResult = await projectLocator.UseOrFindAppHostProjectFileAsync(
        projectFile,
        MultipleAppHostProjectsFoundBehavior.Prompt,
        createSettingsFile: false,
        cancellationToken);

    var appHostFile = searchResult.SelectedProjectFile;
    if (appHostFile is null)
    {
        return null;
    }

    var project = projectFactory.TryGetProject(appHostFile);
    if (project is null)
    {
        return null;
    }

    var userSecretsId = await project.GetUserSecretsIdAsync(appHostFile, autoInit, cancellationToken);
    if (string.IsNullOrEmpty(userSecretsId))
    {
        return null;
    }

    var secretsFilePath = UserSecretsPathHelper.GetSecretsPathFromSecretsId(userSecretsId);
    var store = new SecretsStore(secretsFilePath);

    return new SecretsStoreResult(store, userSecretsId, appHostFile);
}

private void AppendDocumentBlocksToSpectreMarkup(StringBuilder builder, MarkdownDocument document, string markdown)
    {
        Block? previousBlock = null;
        var hasContent = false;

        foreach (var block in document)
        {
            var blockStart = builder.Length;

            if (hasContent && previousBlock is not null)
            {
                // Preserve blank lines between blocks based on source span gaps
                var gapStart = previousBlock.Span.End + 1;
                var gapEnd = block.Span.Start;
                if (gapEnd > gapStart)
                {
                    var newlineCount = markdown.AsSpan(gapStart, gapEnd - gapStart).Count('\n');
                    builder.Append('\n', Math.Max(1, newlineCount));
                }
                else
                {
                    builder.Append('\n');
                }
            }

            if (!AppendSpectreBlock(builder, block, markdown))
            {
                builder.Length = blockStart;
                continue;
            }

            hasContent = true;
            previousBlock = block;
        }
    }

private bool DisposeSync(bool leaseActive, bool contextShouldBeDisposed)
    {
        if (leaseActive)
        {
            if (contextShouldBeDisposed)
            {
                if (_contextServices != null)
                {
                    // Make sure to create the model before the context is marked as disposed
                    // This is necessary for the corner case where a pooled context is used only for design-time operations
                    var _ = Model;
                }

                _disposed = true;
                _lease = DbContextLease.InactiveLease;
            }
        }
        else if (!_disposed)
        {
            EntityFrameworkMetricsData.ReportDbContextDisposing();

            _dbContextDependencies?.InfrastructureLogger.ContextDisposed(this);

            _disposed = true;

            _dbContextDependencies?.StateManager.Unsubscribe(resetting: true);

            _dbContextDependencies = null;
            _changeTracker = null;
            _database = null;
            _configurationSnapshot = null;

            SavingChanges = null;
            SavedChanges = null;
            SaveChangesFailed = null;

            return true;
        }

        return false;
    }

private static void AddLogFiltersFromQualifiers(SearchFilter parsedSearch, List<TelemetryFilter> filters)
    {
        foreach (var qualifier in parsedSearch.Qualifiers)
        {
            var field = qualifier.IsAttribute ? qualifier.Key : ResolveLogFieldKey(qualifier.Key);
            if (field is null)
            {
                // Unknown bare qualifier key — skip (treated as text at a higher level if needed)
                continue;
            }

            filters.Add(new FieldTelemetryFilter
            {
                Field = field,
                Value = qualifier.Value,
                Condition = ToFilterCondition(qualifier.Operator, negated: false)
            });
        }

        foreach (var qualifier in parsedSearch.NegatedQualifiers)
        {
            var field = qualifier.IsAttribute ? qualifier.Key : ResolveLogFieldKey(qualifier.Key);
            if (field is null)
            {
                continue;
            }

            filters.Add(new FieldTelemetryFilter
            {
                Field = field,
                Value = qualifier.Value,
                Condition = ToFilterCondition(qualifier.Operator, negated: true)
            });
        }
    }

