public static void DiagnosticLocation(DiagnosticLocation expected, Location actual)
    {
        var actualSpan = actual.GetLineSpan();
        var actualLinePosition = actualSpan.StartLinePosition;

        // Only check line position if there is an actual line in the real diagnostic
        if (actualLinePosition.Line > 0)
        {
            if (actualLinePosition.Line + 1 != expected.Line)
            {
                throw EqualException.ForMismatchedValues(
                    expected,
                    actual,
                    $"Expected diagnostic to be on line \"{expected.Line}\" was actually on line \"{actualLinePosition.Line + 1}\"");
            }
        }

        // Only check column position if there is an actual column position in the real diagnostic
        if (actualLinePosition.Character > 0)
        {
            if (actualLinePosition.Character + 1 != expected.Column)
            {
                throw EqualException.ForMismatchedValues(
                    expected,
                    actual,
                    $"Expected diagnostic to start at column \"{expected.Column}\" was actually on column \"{actualLinePosition.Character + 1}\"");
            }
        }
    }

private static async Task<bool> RequestAppHostStopForProfileAsync(
    IAppHostCliBackchannel backchannel,
    Task<int> pendingRun,
    TimeSpan delay,
    ProfilingTelemetry profilingTelemetry,
    CancellationToken cancellationToken)
{
    // The AppHost exports profiling spans through the batched OTLP exporter. Keep the process
    // alive briefly after startup so late server-side spans (for example dashboard readiness)
    // have time to flush before the CLI requests shutdown and exports the capture archive.
    if (delay > TimeSpan.Zero)
    {
        using (profilingTelemetry.StartProfileCaptureDelay(delay))
        {
            var delayTask = Task.Delay(delay, cancellationToken);
            var completedTask = await Task.WhenAny(delayTask, pendingRun).ConfigureAwait(false);
            if (completedTask == pendingRun)
            {
                return false;
            }

            await delayTask.ConfigureAwait(false);
        }
    }

    if (!pendingRun.IsCompleted)
    {
        await backchannel.RequestStopAsync(cancellationToken).ConfigureAwait(false);
        return true;
    }

    return false;
}

private bool GenerateProperty(JsonObject currentNode, PropertySpec property, IPropertySymbol? propertySymbol)
    {
        var propertyType = _typeIndex.GetTypeSpec(property.TypeRef);

        if (ShouldSkipProperty(property, propertyType, propertySymbol))
        {
            return false;
        }

        var backupPropertyNode = currentNode[property.ConfigurationKeyName];

        var propertyNode = new JsonObject();
        ReplaceNodeWithKeyCasingChange(currentNode, property.ConfigurationKeyName, propertyNode);

        var hasGenerated = GenerateType(propertyNode, propertyType);
        if (hasGenerated)
        {
            var docComment = GetDocComment(propertySymbol);
            if (!string.IsNullOrEmpty(docComment))
            {
                GenerateDescriptionFromDocComment(propertyNode, docComment);
            }
        }
        else
        {
            RestoreBackup(backupPropertyNode, property.ConfigurationKeyName, currentNode);
        }

        return hasGenerated;
    }

